def dinner_party():
    guests = []
    topics = []

    while True:
        guest = input("Enter a guest for the dinner party: ")
        if guest == "done":
            break
        guests.append(guest)

        topic = input("Enter a topic for discussion with " + guest + ": ")
        topics.append(topic)

    for i in range(len(guests)):
        print("Dinner with " + guests[i])
        print("Topic: " + topics[i])

